import { useEffect, useState } from "react";

export default function DuckHunt() {
  const [visible, setVisible] = useState(true);
  const [score, setScore] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setVisible(Math.random() < 0.5);
    }, 1000);

    return () => clearInterval(id);
  }, []);

  function shoot() {
    if (!visible) return;

    setScore(score + 1);
    setVisible(false);
  }

  return (
    <div className="container">
      <h1>🔫 Shooting Game</h1>

      <h2>Score: {score}</h2>

      <div
        style={{
          width: 400,
          height: 300,
          border: "2px solid black",
          display: "grid",
          placeItems: "center",
          cursor: "crosshair",
          userSelect: "none",
        }}
      >
        {visible && (
          <div
            onClick={shoot}
            style={{
              fontSize: "5rem",
              cursor: "crosshair",
            }}
          >
            🦆
          </div>
        )}
      </div>
    </div>
  );
}
